// Validate payload (structure, ts, values)
if (!msg.payload || typeof msg.payload !== 'object' || Array.isArray(msg.payload) || Object.keys(msg.payload).length === 0) {
    msg.statusCode = 400;
    msg.payload = { status: 'error', reason: 'body not valid JSON object' };
    return [null, msg];
}

const ts = msg.payload.ts;
const values = msg.payload.values;
if (typeof ts !== 'number' || !Number.isFinite(ts)) {
    msg.statusCode = 400;
    msg.payload = { status: 'error', reason: 'ts missing or not finite number' };
    return [null, msg];
}

const now = Date.now();
if (ts < now - 30*24*3600*1000 || ts > now + 5*60*1000) {
    msg.statusCode = 400;
    msg.payload = { status: 'error', reason: 'ts outside acceptable window (now-30d .. now+5min)' };
    return [null, msg];
}

if (typeof values !== 'object' || values === null || Array.isArray(values) || Object.keys(values).length === 0) {
    msg.statusCode = 400;
    msg.payload = { status: 'error', reason: 'values must be non-empty object' };
    return [null, msg];
}

const validValues = {};
for (const [tag, value] of Object.entries(values)) {
    if (value === null || value === undefined) continue;
    validValues[tag] = value;
}

const fs = global.get('fs');
const runtimeConfigPath = env.get('NR_RUNTIME_CONFIG_PATH') || '/data/runtime_config.json';

function loadRuntimeConfig() {
    const cached = flow.get('runtimeConfigCache') || { raw: null, config: {} };
    if (!fs) return { config: cached.config || {}, changed: false };
    try {
        const raw = fs.readFileSync(runtimeConfigPath, 'utf8');
        if (raw !== cached.raw) {
            let parsed;
            try {
                parsed = JSON.parse(raw);
            } catch (err) {
                node.warn('runtime_config parse error: ' + err.message);
                return { config: cached.config || {}, changed: false };
            }
            const cfg = {};
            if (Array.isArray(parsed.expected_tags)) {
                cfg.expected_tags = parsed.expected_tags.filter(t => typeof t === 'string');
            }
            if (typeof parsed.ai_inference_url === 'string' && parsed.ai_inference_url.trim().length > 0) {
                cfg.ai_inference_url = parsed.ai_inference_url.trim();
            }
            if (typeof parsed.inference_emit_interval_ms === 'number' && Number.isFinite(parsed.inference_emit_interval_ms) && parsed.inference_emit_interval_ms > 0) {
                cfg.inference_emit_interval_ms = parsed.inference_emit_interval_ms;
            }
            flow.set('runtimeConfigCache', { raw: raw, config: cfg });
            return { config: cfg, changed: true };
        }
        return { config: cached.config || {}, changed: false };
    } catch (_err) {
        if (cached.raw !== null) {
            flow.set('runtimeConfigCache', { raw: null, config: {} });
            return { config: {}, changed: true };
        }
        return { config: {}, changed: false };
    }
}

const runtimeLoad = loadRuntimeConfig();
const expectedTags = runtimeLoad.config.expected_tags;

// Reset lastSeen only if expected_tags set actually changed (adding other
// runtime-config keys like inference_emit_interval_ms must NOT force warmup).
let lastSeen = flow.get('lastSeen') || {};
if (runtimeLoad.changed) {
    const prevTags = (flow.get('prevExpectedTags') || []).slice().sort().join(',');
    const newTags  = (expectedTags || []).slice().sort().join(',');
    if (prevTags !== newTags) {
        lastSeen = {};
        flow.set('prevExpectedTags', expectedTags || []);
    }
}

// Update LOCF state
for (const [tag, value] of Object.entries(validValues)) {
    const prev = lastSeen[tag];
    if (!prev || ts >= prev.ts) {
        lastSeen[tag] = { value: value, ts: ts };
    }
}
flow.set('lastSeen', lastSeen);

// Fan-out to TB gateway (event-driven)
const DEVICE_PROFILE = flow.get('DEVICE_PROFILE') || 'sensor_planta';
const seen = flow.get('connectedDevices') || {};
const gatewayMsgs = [];
for (const tagName of Object.keys(validValues)) {
    if (!seen[tagName]) {
        gatewayMsgs.push({
            payload: JSON.stringify({ device: tagName, type: DEVICE_PROFILE }),
            topic: 'v1/gateway/connect',
            qos: 1
        });
        seen[tagName] = true;
    }
}
const gatewayPayload = {};
for (const [tag, value] of Object.entries(validValues)) {
    gatewayPayload[tag] = [{ ts: ts, values: { value: value } }];
}
gatewayMsgs.push({
    payload: JSON.stringify(gatewayPayload),
    topic: 'v1/gateway/telemetry',
    qos: 1
});
flow.set('connectedDevices', seen);

msg.statusCode = 200;
msg.payload = { status: 'ok', tags: Object.keys(validValues).length };
return [gatewayMsgs, msg];

// Periodic emit to AI. Inject fires at 1s heartbeat; gate emits at most
// once every inference_emit_interval_ms (default 40000).
// LOCF only: if all expected_tags are in lastSeen → emit; else skip silently.
// No TTL, no warmup timeout, no exposed counters.

const fs = global.get('fs');
const runtimeConfigPath = env.get('NR_RUNTIME_CONFIG_PATH') || '/data/runtime_config.json';

function loadRuntimeConfig() {
    const cached = flow.get('runtimeConfigCache') || { raw: null, config: {} };
    if (!fs) return cached.config || {};
    try {
        const raw = fs.readFileSync(runtimeConfigPath, 'utf8');
        if (raw === cached.raw) return cached.config || {};
        let parsed;
        try {
            parsed = JSON.parse(raw);
        } catch (err) {
            node.warn('runtime_config parse error: ' + err.message);
            return cached.config || {};
        }
        const cfg = {};
        if (Array.isArray(parsed.expected_tags)) cfg.expected_tags = parsed.expected_tags.filter(t => typeof t === 'string');
        if (typeof parsed.ai_inference_url === 'string' && parsed.ai_inference_url.trim().length > 0) cfg.ai_inference_url = parsed.ai_inference_url.trim();
        if (typeof parsed.inference_emit_interval_ms === 'number' && parsed.inference_emit_interval_ms > 0) cfg.inference_emit_interval_ms = parsed.inference_emit_interval_ms;
        flow.set('runtimeConfigCache', { raw: raw, config: cfg });
        // Mirror the lastSeen reset from fn_main for config changes
        const prevTags = (flow.get('prevExpectedTags') || []).slice().sort().join(',');
        const newTags  = (cfg.expected_tags || []).slice().sort().join(',');
        if (prevTags !== newTags) {
            flow.set('lastSeen', {});
            flow.set('prevExpectedTags', cfg.expected_tags || []);
        }
        return cfg;
    } catch (_err) {
        if (cached.raw !== null) {
            flow.set('runtimeConfigCache', { raw: null, config: {} });
        }
        return {};
    }
}

const cfg = loadRuntimeConfig();
const EMIT_INTERVAL = cfg.inference_emit_interval_ms || 40000;
const expectedTags = cfg.expected_tags;
const aiUrl = cfg.ai_inference_url;

// Rate-limit gate: emit at most once per EMIT_INTERVAL ms. Inject is a 1s
// heartbeat; this makes the effective cadence configurable via runtime_config.
const now = Date.now();
const lastEmitAttempt = flow.get('lastEmitAttemptTs') || 0;
if (now - lastEmitAttempt < EMIT_INTERVAL) return null;
flow.set('lastEmitAttemptTs', now);

// Fail-closed: no expected_tags → no emit
if (!Array.isArray(expectedTags) || expectedTags.length === 0) return null;

const lastSeen = flow.get('lastSeen') || {};
const missing = expectedTags.filter(t => !(t in lastSeen));
if (missing.length > 0) {
    node.log('emit skipped: warmup, ' + missing.length + '/' + expectedTags.length + ' tags not yet seen');
    return null;
}

// Build snapshot with LOCF values. ts = wall-clock per spec.
const snapshot = {};
for (const t of expectedTags) snapshot[t] = lastSeen[t].value;

if (!aiUrl) return null;

return {
    payload: { ts: now, sensors: snapshot },
    url: aiUrl,
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    requestTimeout: 5000
};
